import React, { useEffect, useState } from 'react'
import { farmService } from '../../services/api'

const OwnerFarms = () => {
  const [farms, setFarms] = useState([])
  const [loading, setLoading] = useState(false)
  const [editingId, setEditingId] = useState(null)
  const [error, setError] = useState('')

  const loadFarms = async () => {
    setLoading(true)
    try {
      const res = await farmService.getFarms()
      setFarms(res.data.data || [])
    } catch (err) {
      setError(err.response?.data?.message || err.message)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => { loadFarms() }, [])

  const handleEdit = (farm) => {
    setEditingId(farm.farm_id)
    // navigate to create page with editing? For now inline edit reuses modal logic below
    setTimeout(() => {
      setEditingId(null)
      loadFarms()
    }, 0)
  }

  const handleDelete = async (farmId) => {
    if (!window.confirm('Bạn có chắc chắn muốn xóa trại này?')) return
    try {
      await farmService.deleteFarm(farmId)
      await loadFarms()
    } catch (err) {
      setError(err.response?.data?.message || err.message)
    }
  }

  return (
    <div style={{ padding: 20 }}>
      <h2>Quản lý Trại nuôi</h2>
      {error && <div className="alert alert-error">{error}</div>}

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20 }}>
        <div>
          <h2>Quản lý Trại nuôi</h2>
          <p style={{ margin: 0, color: '#666' }}>Tạo, sửa và xóa trại. Tạo trại tách riêng.</p>
        </div>
        <div style={{ display: 'flex', gap: 8 }}>
          <a href="/owner/farms/create" className="btn btn-primary">+ Tạo trại mới</a>
        </div>
      </div>

      <h3>Danh sách trại</h3>
      {loading ? (
        <p>Đang tải...</p>
      ) : (
        <table className="table">
          <thead>
            <tr>
              <th>#</th>
              <th>Mã</th>
              <th>Tên</th>
              <th>Địa điểm</th>
              <th>Diện tích (ha)</th>
              <th>Hành động</th>
            </tr>
          </thead>
          <tbody>
            {farms.map((f, idx) => (
              <tr key={f.farm_id}>
                <td>{idx + 1}</td>
                <td>{f.farm_code}</td>
                <td>{f.farm_name}</td>
                <td>{f.location}</td>
                <td>{f.area_hectare}</td>
                <td>
                  <a className="btn" href={`/owner/farms/create?edit=${f.farm_id}`}>Sửa</a>
                  <button className="btn btn-danger" onClick={() => handleDelete(f.farm_id)}>Xóa</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  )
}

export default OwnerFarms
